+    #[test]
+    fn test_get_miss_increments() {
+        let mut cache: LfuCache<&str, i32> = LfuCache::new(5);
+        cache.get(&"x");
+        cache.get(&"y");
+        cache.get(&"z");
+        let stats = cache.stats();
+        assert_eq!(stats.misses, 3);
+        assert_eq!(stats.hits, 0);
+    }
