+    #[test]
+    fn test_multiple_evictions() {
+        let mut cache = LfuCache::new(2);
+        cache.insert("a", 1);
+        cache.insert("b", 2);
+        let ev1 = cache.insert("c", 3); // evicts a
+        assert_eq!(ev1, Some(("a", 1)));
+        let ev2 = cache.insert("d", 4); // evicts b or c (both freq=1, b is older)
+        assert_eq!(ev2, Some(("b", 2)));
+    }
