+        let mut cache = LfuCache::new(5);
+        cache.insert("a", 1);
+        assert_eq!(cache.frequency(&"a"), Some(1));
+        cache.get(&"a");
+        assert_eq!(cache.frequency(&"a"), Some(2));
+        cache.get(&"a");
+        cache.get(&"a");
+        assert_eq!(cache.frequency(&"a"), Some(4));
+    }
