+        cache.insert("a", 1);
+        let stats = cache.stats();
+        assert_eq!(stats.min_frequency, 1); // just inserted
+        cache.get(&"a"); // freq=2
+        cache.insert("b", 2); // min_frequency resets to 1
+        let stats = cache.stats();
+        assert_eq!(stats.min_frequency, 1);
